function identity<T>(value: T): T {
  return value
}

const result = identity(42)

// TypeScript решает уравнение:
// value: T = 42: number
// Значит T = number

const result = identity(42) // identity<number>(42)

// result получает тип T[T=number] = number
const result = identity(42) // тип: number

// Теперь TypeScript знает:
console.log(result.toFixed(2)) // OK — number имеет метод toFixed
// result.toUpperCase()          // Ошибка — number не имеет toUpperCase

function getLength<T extends { length: number }>(x: T): number {
  return x.length
}

getLength('hello')    // T = string (у строки есть length)
getLength([1, 2, 3]) // T = number[] (у массива есть length)
// getLength(42)     // Ошибка! number не имеет length
